queries.sparql:
PREFIX : <http://ambrosia.example.org/journalism#>
PREFIX p: <http://ambrosia.example.org/journalism/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?id ?role ?name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasParticipants ?child ; p:hasPress_Conferences ?parent . } GROUP BY ?child }
  ?child p:id ?id .
  ?child p:role ?role .
  ?child p:name ?name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Press_Conferences } }
  FILTER(?nf = ?total)
}

